#include<bits/stdc++.h>
using namespace std;
long long n;
long long a[201],f[201][201],g[201][201];
char c[201];
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        cin>>c[i]>>a[i];
        c[i+n]=c[i];
        a[i+n]=a[i];
    }
    memset(f,-0x3f,sizeof(f));
    memset(g,0x3f,sizeof(g));
    for(long long i=1;i<=n*2;i++)
    {
        f[i][i]=g[i][i]=a[i];
    }
    for(long long len=2;len<=n;len++)
    {
        for(long long l=1,r=len;r<=n*2;l++,r++)
        {
            for(long long k=l;k<r;k++)
            {
                if(c[k+1]=='t')
                {
                    f[l][r]=max(f[l][r],f[l][k]+f[k+1][r]);
                    g[l][r]=min(g[l][r],g[l][k]+g[k+1][r]);
                }
                else
                {
                    f[l][r]=max({f[l][r],f[l][k]*f[k+1][r],f[l][k]*g[k+1][r],g[l][k]*f[k+1][r],g[l][k]*g[k+1][r]});
                    g[l][r]=min({g[l][r],f[l][k]*f[k+1][r],f[l][k]*g[k+1][r],g[l][k]*f[k+1][r],g[l][k]*g[k+1][r]});
                }
            }
        }
    }
    long long ans=-1e18;
    for(long long i=1;i<=n;i++)
    {
        ans=max(ans,f[i][i+n-1]);
    }
    printf("%lld\n",ans);
    for(long long i=1;i<=n;i++)
    {
        if(f[i][i+n-1]==ans)
        {
            printf("%lld ",i);
        }
    }
    return 0;
}
